findings.codeql_raw_query:
/**
 * @name XSS via error messages including request data
 * @description Exception messages or error pages that include request parameters without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-error-pages
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ErrorXSSConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // setAttribute on request/session - used to pass error messages to JSP pages
    exists(MethodCall mc |
      mc.getMethod().hasName("setAttribute") and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet", "ServletRequest") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpSession")
      ) and
      sink.asExpr() = mc.getArgument(1)
    )
  }
}

module ErrorXSSFlow = TaintTracking::Global<ErrorXSSConfig>;
import ErrorXSSFlow::PathGraph

from ErrorXSSFlow::PathNode source, ErrorXSSFlow::PathNode sink
where ErrorXSSFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User input from $@ stored in request/session attribute - may be displayed in HTML without encoding.", source.getNode(), "user input"
